// Simple markdown-ish renderer
function renderContent(text) {
  // Code blocks
  text = text.replace(/```[\w]*\n?([\s\S]*?)```/g, (_, code) => `<pre><code>${escapeHtml(code.trim())}</code></pre>`);
  // Inline code
  text = text.replace(/`([^`]+)`/g, (_, c) => `<code>${escapeHtml(c)}</code>`);
  // Bold
  text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  // Line breaks
  text = text.replace(/\n/g, '<br/>');
  return text;
}

function escapeHtml(str) {
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

export default function GroqChatbot() {
  const [apiKey, setApiKey] = useState("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");
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const bottomRef = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  const autoResize = () => {
    const ta = textareaRef.current;
    if (!ta) return;
    ta.style.height = "auto";
    ta.style.height = Math.min(ta.scrollHeight, 160) + "px";
  };

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading) return;
    if (!apiKey.trim()) {
      setError("Please enter your Groq API key above.");
      return;
    }

    setError("");
    const newMessages = [...messages, { role: "user", content: text }];
    setMessages(newMessages);
    setInput("");
    if (textareaRef.current) textareaRef.current.style.height = "48px";
    setLoading(true);

    try {
      const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${apiKey.trim()}`,
        },
        body: JSON.stringify({
          model: "llama-3.1-8b-instant",
          messages: newMessages,
          temperature: 0.7,
          max_tokens: 1024,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data?.error?.message || `HTTP ${res.status}`);
      }

      const reply = data.choices?.[0]?.message?.content || "No response.";
      setMessages([...newMessages, { role: "assistant", content: reply }]);
    } catch (err) {
      setError(`Error: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="app">
        <div className="bg-grid" />

        {/* Header */}
        <div className="header">
          <div className="header-left">
            <div className="logo-dot" />
            <span className="logo-text">GROQ<span>CHAT</span></span>
          </div>
          <span className="model-badge">llama-3.1-8b-instant</span>
        </div>

        {/* API Key */}
        <div className="api-setup">
          <label>API KEY</label>
          <input
            className="api-input"
            type="password"
            placeholder="gsk_xxxxxxxxxxxxxxxxxxxxxxxx"
            value={apiKey}
            onChange={e => setApiKey(e.target.value)}
          />
        </div>

        {/* Messages */}
        <div className="messages-container">
          {messages.length === 0 && !loading && (
            <div className="empty-state">
              <div className="empty-icon">⚡</div>
              <p>Powered by Groq's ultra-fast inference.<br/>Enter your API key and start chatting.</p>
            </div>
          )}

          {messages.map((msg, i) => (
            <div key={i} className={`message ${msg.role}`}>
              <div className="avatar">{msg.role === "user" ? "U" : "AI"}</div>
              <div
                className="bubble"
                dangerouslySetInnerHTML={{ __html: renderContent(msg.content) }}
              />
            </div>
          ))}

          {loading && (
            <div className="message assistant">
              <div className="avatar">AI</div>
              <div className="bubble">
                <div className="typing-indicator">
                  <span/><span/><span/>
                </div>
              </div>
            </div>
          )}

          {error && <div className="error-msg">{error}</div>}
          <div ref={bottomRef} />
        </div>

        {/* Input */}
        <div className="input-area">
          <div className="input-row">
            <div className="textarea-wrap">
              <textarea
                ref={textareaRef}
                className="chat-input"
                placeholder="Type a message... (Enter to send, Shift+Enter for newline)"
                value={input}
                onChange={e => { setInput(e.target.value); autoResize(); }}
                onKeyDown={handleKeyDown}
                rows={1}
              />
            </div>
            <button
              className="send-btn"
              onClick={sendMessage}
              disabled={loading || !input.trim()}
            >
              <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z"/>
              </svg>
            </button>
          </div>
          <p className="hint">↑ Free API keys at console.groq.com</p>
        </div>
      </div>
    </>
  );
}
